/// Length of the B-tensor's parent dimension for a given step.
pub const fn k_parent_for(step: usize) -> usize {
    match step {
        0 => 12,
        1 => 9,
        2 => 7,
        3 => 5,
        _ => 0,
    }
}

/// Length of the B-tensor's child dimension for a given step.
pub const fn k_child_for(step: usize) -> usize {
    match step {
        0 => 9,
        1 => 7,
        2 => 5,
        3 => 3,
        _ => 0,
    }
}
